public partial class BaseTest
{
        public object helperStrToBinary5(Exchange exchange, object str)
        {
            return exchange.base64ToBinary(exchange.stringToBase64(str));
        }
        public void testBinaryToBase58()
        {
            var exchange = new ccxt.Exchange(new Dictionary<string, object>() {
                { "id", "sampleexchange" },
            });
            Assert(isEqual(exchange.parseNumber(null), null), "GO skip trick");
            Assert("GO_SKIP_START");
            // Test 1: Simple string
            object binary1 = helperStrToBinary5(exchange, "hello");
            Assert(isEqual(exchange.binaryToBase58(binary1), "Cn8eVZg"));
            // Test 2: String with space
            object binary2 = helperStrToBinary5(exchange, "hello world");
            Assert(isEqual(exchange.binaryToBase58(binary2), "StV1DL6CwTryKyV"));
            // Test 3: Short string
            object binary3 = helperStrToBinary5(exchange, "test");
            Assert(isEqual(exchange.binaryToBase58(binary3), "3yZe7d"));
            // Test 4: Single byte
            object binary4 = helperStrToBinary5(exchange, "a");
            Assert(isEqual(exchange.binaryToBase58(binary4), "2g"));
            // Test 5: Two bytes
            object binary5 = helperStrToBinary5(exchange, "ab");
            Assert(isEqual(exchange.binaryToBase58(binary5), "8Qq"));
            // Test 6: Three bytes
            object binary6 = helperStrToBinary5(exchange, "abc");
            Assert(isEqual(exchange.binaryToBase58(binary6), "ZiCa"));
            // Test 7: JSON-like binary
            object binary7 = helperStrToBinary5(exchange, "{\"key\":\"value\"}");
            Assert(isEqual(exchange.binaryToBase58(binary7), "4SoiMiEYtTt5tPdi81Fik"));
            Assert("GO_SKIP_END");
        }
}